import {
BrowserRouter,
Routes,
Route
} from "react-router-dom";

import Login from "./components/Login";
import EmployeeList from "./components/EmployeeList";

function App(){

 return(
  <BrowserRouter>

   <Routes>

    <Route
    path="/"
    element={<Login />}
    />

    <Route
    path="/employees"
    element={<EmployeeList />}
    />

   </Routes>

  </BrowserRouter>
 );
}

export default App;
